// Clean and prepare document content for AI compliance scoring
const rawContent = $input.item.json.data || '';
const docMeta = $input.item.json;

// Strip HTML tags if present, normalize whitespace
const cleanContent = rawContent
  .replace(/<[^>]*>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

// Truncate to ~6000 chars to stay within token limits
const truncated = cleanContent.length > 6000
  ? cleanContent.substring(0, 6000) + '... [truncated for analysis]'
  : cleanContent;

const wordCount = cleanContent.split(/\s+/).length;
const hasCodeBlocks = rawContent.includes('```') || rawContent.includes('<code>');
const hasHeaders = rawContent.includes('#') || /<h[1-6]/i.test(rawContent);
const hasExamples = /example|sample|e\.g\.|for instance/i.test(cleanContent);
const hasWarnings = /warning|caution|note|important|deprecated/i.test(cleanContent);

return {
  json: {
    doc_title: docMeta.doc_title || 'Untitled Document',
    doc_type: docMeta.doc_type || 'Unknown',
    doc_url: docMeta.doc_url || '',
    review_date: docMeta.review_date || new Date().toISOString().split('T')[0],
    clean_content: truncated,
    word_count: wordCount,
    pre_analysis: {
      has_code_blocks: hasCodeBlocks,
      has_headers: hasHeaders,
      has_examples: hasExamples,
      has_warnings: hasWarnings
    }
  }
};

